/**
 * Generate activity test data based on pattern
 *
 * @param pattern - The test data pattern to generate
 * @param overrides - Optional field overrides
 * @returns Generated test data
 *
 * @example
 * ```typescript
 * // Generate complete test data
 * const data = generateActivityTestData('complete');
 *
 * // Generate unique test data with overrides
 * const customData = generateActivityTestData('unique', {
 *   is_active: false,
 * });
 * ```
 */
export function generateActivityTestData(
  pattern: TestDataPattern = 'complete',
  overrides: Partial<ActivityCreateRequest> = {}
): ActivityCreateRequest {
  let baseData: ActivityCreateRequest;

  switch (pattern) {
    case 'minimal':
      baseData = { ...minimalActivityFixture };
      break;

    case 'complete':
      baseData = { ...completeActivityFixture };
      break;

    case 'invalid':
      // Return invalid data (caller should handle validation failure)
      baseData = { ...invalidActivityFixture } as ActivityCreateRequest;
      break;

    case 'unique':
      // Generate fresh unique values for each call
      baseData = {
        ...uniqueActivityFixture,
      };
      break;

    default:
      baseData = { ...completeActivityFixture };
  }

  return { ...baseData, ...overrides };
}

